import type { AuthIdentity, StoreRecord, StoreRoleField } from './types';

const ROLE_FIELDS: StoreRoleField[] = [
  'id',
  'ownerId',
  'ownerUid',
  'userId',
  'uid',
  'ownerEmail',
  'email',
  'userEmail',
  'adminEmails'
];

function normalizeEmail(value: unknown): string {
  return String(value ?? '').trim().toLowerCase();
}

function normalizeUid(value: unknown): string {
  return String(value ?? '').trim();
}

export function getStoreRoleFields(): StoreRoleField[] {
  return [...ROLE_FIELDS];
}

export function storeBelongsToAuth(store: StoreRecord | null | undefined, auth: AuthIdentity): boolean {
  if (!store) return false;

  const uid = normalizeUid(auth.uid);
  const email = normalizeEmail(auth.email);
  const adminEmails = Array.isArray(store.adminEmails)
    ? store.adminEmails.map(normalizeEmail).filter(Boolean)
    : [];

  return [
    normalizeUid(store.id),
    normalizeUid(store.ownerId),
    normalizeUid(store.ownerUid),
    normalizeUid(store.userId),
    normalizeUid(store.uid)
  ].includes(uid) || [
    normalizeEmail(store.ownerEmail),
    normalizeEmail(store.email),
    normalizeEmail(store.userEmail)
  ].includes(email) || adminEmails.includes(email);
}

type QuerySnapshotLike = {
  empty: boolean;
  docs: Array<{ id: string; data(): Record<string, unknown> }>;
};

type DocSnapshotLike = {
  exists: boolean;
  id: string;
  data(): Record<string, unknown> | undefined;
};

type FirestoreLike = {
  collection(name: string): {
    where(field: string, op: '==' | 'array-contains', value: string): {
      limit(count: number): { get(): Promise<QuerySnapshotLike> };
    };
    doc(id: string): { get(): Promise<DocSnapshotLike> };
  };
};

export async function resolveStoreForFirebaseUser(
  db: FirestoreLike,
  auth: AuthIdentity,
  options?: { knownIds?: string[] }
): Promise<(StoreRecord & { id: string }) | null> {
  const knownIds = (options?.knownIds || []).map(normalizeUid).filter(Boolean);

  for (const knownId of knownIds) {
    try {
      const doc = await db.collection('stores').doc(knownId).get();
      const data = doc.data() || {};
      if (doc.exists && storeBelongsToAuth({ id: doc.id, ...data }, auth)) {
        return { id: doc.id, ...data };
      }
    } catch {
      // segue para as queries por ownership
    }
  }

  const email = normalizeEmail(auth.email);
  const uid = normalizeUid(auth.uid);
  const attempts: Array<() => Promise<QuerySnapshotLike>> = [];

  if (email) {
    attempts.push(
      () => db.collection('stores').where('ownerEmail', '==', email).limit(1).get(),
      () => db.collection('stores').where('adminEmails', 'array-contains', email).limit(1).get(),
      () => db.collection('stores').where('email', '==', email).limit(1).get(),
      () => db.collection('stores').where('userEmail', '==', email).limit(1).get()
    );
  }

  if (uid) {
    attempts.push(
      () => db.collection('stores').where('ownerId', '==', uid).limit(1).get(),
      () => db.collection('stores').where('ownerUid', '==', uid).limit(1).get(),
      () => db.collection('stores').where('userId', '==', uid).limit(1).get(),
      () => db.collection('stores').where('uid', '==', uid).limit(1).get()
    );
  }

  for (const attempt of attempts) {
    const snap = await attempt();
    if (!snap.empty) {
      const doc = snap.docs[0];
      if (!doc) continue;
      const data = doc.data() || {};
      if (storeBelongsToAuth({ id: doc.id, ...data }, auth)) {
        return { id: doc.id, ...data };
      }
    }
  }

  return null;
}
